// =========================================================
// Normaliza linhas do XLSX para o formato esperado pelo RPC
// fn_supest_ingest_snapshots.
//   - extrai snapshot_date do filename
//   - mapeia colunas Excel -> campos do RPC
//   - mantém valores como string (RPC faz parse PT-BR)
// =========================================================

const filename =
  $('Form: upload planilha').first().binary?.['Planilha do dia']?.fileName
  || $('Form: upload planilha').first().json.fileName
  || '';

const m = filename.match(/arquivo-gerado-(\d{2})-(\d{2})-(\d{4})/);
if (!m) {
  throw new Error('Não consegui extrair a data do nome do arquivo: ' + filename);
}
const snapshot_date = `${m[3]}-${m[2]}-${m[1]}`;  // YYYY-MM-DD

const COLMAP = {
  'FILIAL':            'filial',
  'TIPO':              'tipo',
  'SETOR':             'setor',
  'DEPARTAMENTO':      'departamento',
  'SECAO':             'secao',
  'FORNECEDOR':        'fornecedor',
  'Grade Secao':       'grade',
  'Grade Extra':       'grade_extra',
  'Qtd Estoque':       'estoque',
  'Vlr. Estoque R$':   'vlr_estoque',
  'Qtd Reservado':     'qtd_reservado',
  'Qtd Transito CD':   'qtd_transito_cd',
  'Qtd Est Total':     'qtd_estoque_total',
  'Qtde Total Vendas': 'quant_vendas',
  'Qtd Media Dia':     'media_dia',
  'Qtd Movimentos':    'quant_movimentos',
  'QTDDIASMOV':        'dias_venda',
  'Qtd Maximo':        'maximo',
  'Dt. Ult. Ent.':     'ultima_entrada',
  'Dt. Ult. Sai':      'ultima_saida',
  'MIX':               'mix',
  'QTDDIAS':           'giro',
};

function splitProduto(v) {
  if (v == null) return [null, null];
  const s = String(v);
  const mm = s.match(/^(\d+)\s*-\s*(.*)$/);
  if (!mm) return [s, null];
  return [mm[1], mm[2].trim()];
}

function toStr(v) {
  if (v == null) return null;
  if (typeof v === 'string') return v;
  return String(v);
}

const out = [];
for (const it of items) {
  const row = it.json;
  const rec = { snapshot_date };
  for (const [excel, target] of Object.entries(COLMAP)) {
    rec[target] = toStr(row[excel]);
  }
  const [codigo, desc] = splitProduto(row['PRODUTO']);
  rec.codigo_produto = codigo;
  rec.descricao_produto = desc;
  if (rec.codigo_produto && rec.filial) out.push({ json: rec });
}
return out;

// Agrupa as linhas em pacotes de 1000 (1 item de saída = 1 pacote)
const CHUNK = 1000;
const all = items.map(i => i.json);
const chunks = [];
for (let i = 0; i < all.length; i += CHUNK) {
  chunks.push({
    json: {
      lote: Math.floor(i / CHUNK) + 1,
      total_lotes: Math.ceil(all.length / CHUNK),
      total_linhas: all.length,
      snapshot_date: all[0]?.snapshot_date,
      rows: all.slice(i, i + CHUNK),
    }
  });
}
return chunks;

// Soma os contadores devolvidos pelo RPC a cada lote
const execId = $('Execução: rodando').first().json.id;
const stats = items.reduce((acc, it) => {
  const r = Array.isArray(it.json) ? it.json[0] : it.json;
  acc.inserted += Number(r.inserted_count || 0);
  acc.updated  += Number(r.updated_count  || 0);
  return acc;
}, { inserted: 0, updated: 0 });
return [{ json: { execId, ...stats } }];
